createParty(raidType) {
    if (this.sockets.length === 0) {
        console.log("No more connections available.");
        return;
    }

    let numSocketsToAdd;
    if (raidType === "1by1") {
        numSocketsToAdd = 1;
    } else if (raidType === "xkey") {
        numSocketsToAdd = 3;
    } else {
        console.error("Invalid raid type.");
        return;
    }

    while (this.sockets.length > 0) {
        const party = [];
        const socketsToAdd = this.sockets.slice(0, numSocketsToAdd); // Copy the first numSocketsToAdd elements
        for (const socket of socketsToAdd) {
            const psk = socket.psk;
            party.push({ socket, psk, hasStash: false });
        }

        console.log(`Party ${this.parties.length + 1} created with ${party.length} connections.`);
        this.parties.push(party);
    }
}


There is a fundemental flaw with this script. The sockets are in this.sockets, which is inside altObjects, an object literal. Each socket has a socket.cloneId, and this script keeps making infintie parties and only creates it for the first socket, socket.cloneId is 1

